import (
    "github.com/openmeterio/openmeter/openmeter/event/metadata"
)

const EventVersionSubsystem = "io.openmeter.billing"

type InvoiceCreated struct {
    InvoiceID string `json:"invoiceId"`
}

func (e *InvoiceCreated) EventName() string {
    return EventVersionSubsystem + ".invoice.created/v1"
}

func (e *InvoiceCreated) EventMetadata() metadata.EventMetadata {
    return metadata.EventMetadata{Source: "openmeter/billing-worker", Subject: e.InvoiceID}
}

func (e *InvoiceCreated) Validate() error {
    if e.InvoiceID == "" {
        return errors.New("invoiceId is required")
    }
    return nil
}

import (
    "github.com/openmeterio/openmeter/openmeter/watermill/router"
    "github.com/openmeterio/openmeter/app/config"
)

watermillRouter, err := router.NewDefaultRouter(router.Options{
    Subscriber:  kafkaSubscriber,
    Publisher:   kafkaPublisher, // for DLQ
    Logger:      logger,
    MetricMeter: metricMeter,
    Tracer:      tracer,
    Config: config.ConsumerConfiguration{
        ConsumerGroupName: "billing-worker",
        DLQ: config.DLQConfiguration{Topic: "billing-worker-dlq"},
        Retry: config.RetryConfiguration{
            MaxRetries:      5,
            InitialInterval: 100 * time.Millisecond,
            MaxInterval:     10 * time.Second,
        },
        ProcessingTimeout: 30 * time.Second,
    },
})
if err != nil {
    return nil, fmt.Errorf("create router: %w", err)
}
